// Extract the failed recipient email from each bounce notification.
// Gmail bounce messages include the original recipient address in the body
// and headers. We look for common patterns.

const results = [];

for (const item of $input.all()) {
  const msg = item.json;
  // Combine available text fields to search
  const haystack = [
    msg.snippet || '',
    msg.text || '',
    msg.textPlain || '',
    msg.textHtml || '',
    JSON.stringify(msg.headers || {}),
  ].join(' ');

  // Common bounce patterns for the failed address:
  // "Final-Recipient: rfc822; user@domain.com"
  // "to user@domain.com"
  // "<user@domain.com>: ... not found"
  let failedEmail = null;

  // Pattern 1: Final-Recipient header (most reliable)
  const finalRecipient = haystack.match(/Final-Recipient:\s*rfc822;\s*([^\s<>]+@[^\s<>]+)/i);
  if (finalRecipient) {
    failedEmail = finalRecipient[1];
  }

  // Pattern 2: Original-Recipient header
  if (!failedEmail) {
    const origRecipient = haystack.match(/Original-Recipient:\s*rfc822;\s*([^\s<>]+@[^\s<>]+)/i);
    if (origRecipient) failedEmail = origRecipient[1];
  }

  // Pattern 3: angle-bracket address near failure language
  if (!failedEmail) {
    const bracketMatch = haystack.match(/<([^\s<>]+@[^\s<>]+)>/);
    if (bracketMatch) failedEmail = bracketMatch[1];
  }

  if (failedEmail) {
    // Clean trailing punctuation and lowercase
    failedEmail = failedEmail.replace(/[.,;:>]+$/, '').toLowerCase().trim();
    // Skip our own sender address
    if (!failedEmail.includes('mortgage-digest@jwhfinance.com') &&
        !failedEmail.includes('mailer-daemon') &&
        !failedEmail.includes('postmaster')) {
      results.push({
        json: {
          bouncedEmail: failedEmail,
          messageId: msg.id || null,
          detectedAt: new Date().toISOString(),
        }
      });
    }
  }
}

if (results.length === 0) {
  console.log('[BOUNCE HANDLER] No bounced addresses found in this batch.');
  return [];
}

console.log(`[BOUNCE HANDLER] Found ${results.length} bounced address(es): ${results.map(r => r.json.bouncedEmail).join(', ')}`);
return results;
